  VALUES ?position {
    wd:Q193580  # Governor of New South Wales
    wd:Q193581  # Governor of Victoria
    wd:Q193582  # Governor of Queensland
    wd:Q193583  # Governor of Western Australia
    wd:Q193584  # Governor of South Australia
    wd:Q193585  # Governor of Tasmania
  }
  ?person p:P39 ?statement .
